mapper.select:
select ac.*, sd.dept_name, su.user_name as approver_name from approval_chain ac left join sys_dept sd on ac.dept_id = sd.dept_id left join sys_user su on ac.approver_id = su.user_id
and ac.dept_id = #{deptId} and ac.plan_type = #{planType}
order by ac.dept_id, ac.approval_level, ac.sort_order

mapper.update:
update approval_chain
approval_level = #{approvalLevel}, approver_id = #{approverId}, sort_order = #{sortOrder}, update_by = #{updateBy}, update_time = sysdate()
where id = #{id}
